        // Drain the static notification queue for test isolation
        while (_controller.GetNotifications() is JsonResult jr &&
               jr.Value?.GetType().GetProperty("count")?.GetValue(jr.Value) is int c && c > 0)
        {
            // Already drained by GetNotifications
            break;
        }
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void GetNotifications_ReturnsJsonResult()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsType<JsonResult>(result);
    }

    [Fact]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithZeroCount()
    {
        // Drain any pre-existing notifications
        Services.NotificationServiceTests.DrainQueue();

        // Act
        var result = _controller.GetNotifications();

        // Assert
        var jsonResult = Assert.IsType<JsonResult>(result);
        Assert.NotNull(jsonResult.Value);

        // Check the anonymous object properties via reflection
        var successProp = jsonResult.Value.GetType().GetProperty("success");
        var countProp = jsonResult.Value.GetType().GetProperty("count");
        Assert.True((bool)successProp!.GetValue(jsonResult.Value)!);
        Assert.Equal(0, (int)countProp!.GetValue(jsonResult.Value)!);
    }

    [Fact]
    public void MarkAsRead_ReturnsJsonSuccess()
    {
        // Act
        var result = _controller.MarkAsRead(1);

        // Assert
        var jsonResult = Assert.IsType<JsonResult>(result);
        Assert.NotNull(jsonResult.Value);
        var successProp = jsonResult.Value.GetType().GetProperty("success");
        Assert.True((bool)successProp!.GetValue(jsonResult.Value)!);
    }
}

