using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    [Fact]
    public void Constructor_WithItems_SetsProperties()
    {
        // Arrange
        var items = new List<int> { 1, 2, 3 };

        // Act
        var result = new PaginatedList<int>(items, 10, 2, 3);

        // Assert
        Assert.Equal(2, result.PageIndex);
        Assert.Equal(4, result.TotalPages); // ceil(10/3) = 4
        Assert.Equal(3, result.Count);
        Assert.Contains(1, result);
        Assert.Contains(2, result);
        Assert.Contains(3, result);
    }

    [Theory]
    [InlineData(10, 3, 4)]   // ceil(10/3) = 4
    [InlineData(10, 5, 2)]   // ceil(10/5) = 2
    [InlineData(1, 10, 1)]   // ceil(1/10) = 1
    [InlineData(0, 5, 0)]    // ceil(0/5) = 0
    [InlineData(15, 5, 3)]   // exact division
    public void Constructor_CalculatesTotalPages(int totalCount, int pageSize, int expectedTotalPages)
    {
        // Act
        var result = new PaginatedList<int>(new List<int>(), totalCount, 1, pageSize);

        // Assert
        Assert.Equal(expectedTotalPages, result.TotalPages);
    }

    [Theory]
    [InlineData(1, false)]
    [InlineData(2, true)]
    [InlineData(3, true)]
    public void HasPreviousPage_ReturnsCorrectly(int pageIndex, bool expected)
    {
        // Arrange & Act
        var result = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);

        // Assert
        Assert.Equal(expected, result.HasPreviousPage);
    }

    [Theory]
    [InlineData(1, 3, true)]
    [InlineData(2, 3, true)]
    [InlineData(3, 3, false)]
    public void HasNextPage_ReturnsCorrectly(int pageIndex, int totalPages, bool expected)
    {
        // Arrange - 30 items / 10 per page = 3 pages
        var result = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);

        // Assert
        Assert.Equal(totalPages, result.TotalPages);
        Assert.Equal(expected, result.HasNextPage);
    }

    [Fact]
    public void Create_ReturnsCorrectPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.Equal(2, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.Equal(10, result.Count);
        Assert.Equal(11, result[0]);
        Assert.Equal(20, result[9]);
        Assert.True(result.HasPreviousPage);
        Assert.True(result.HasNextPage);
    }

    [Fact]
    public void Create_FirstPage_HasNoPageBefore()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.Equal(1, result.PageIndex);
        Assert.False(result.HasPreviousPage);
        Assert.True(result.HasNextPage);
        Assert.Equal(1, result[0]);
    }

    [Fact]
    public void Create_LastPage_HasNoPageAfter()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 10);

        // Assert
        Assert.Equal(3, result.PageIndex);
        Assert.True(result.HasPreviousPage);
        Assert.False(result.HasNextPage);
        Assert.Equal(5, result.Count); // last page has 5 items
        Assert.Equal(21, result[0]);
    }

    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.Empty(result);
        Assert.Equal(0, result.TotalPages);
        Assert.False(result.HasPreviousPage);
        Assert.False(result.HasNextPage);
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _sut;

    public NotificationServiceTests()
    {
        _sut = new NotificationService();
        // Drain the static queue to isolate tests
        while (_sut.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        _sut.Dispose();
    }

    [Fact]
    public void SendNotification_Create_EnqueuesNotification()
    {
        // Act
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Contains("John Doe", notification.Message);
        Assert.Contains("created", notification.Message);
        Assert.Equal("Admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_Update_GeneratesCorrectMessage()
    {
        // Act
        _sut.SendNotification("Course", "42", "Chemistry", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("UPDATE", notification.Operation);
        Assert.Contains("Chemistry", notification.Message);
        Assert.Contains("updated", notification.Message);
    }

    [Fact]
    public void SendNotification_Delete_GeneratesCorrectMessage()
    {
        // Act
        _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("DELETE", notification.Operation);
        Assert.Contains("Engineering", notification.Message);
        Assert.Contains("deleted", notification.Message);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Act
        _sut.SendNotification("Student", "99", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("ID: 99", notification.Message);
    }

    [Fact]
    public void SendNotification_WithDisplayName_UsesDisplayNameInMessage()
    {
        // Act
        _sut.SendNotification("Student", "99", "Jane Smith", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("Jane Smith", notification.Message);
        Assert.DoesNotContain("ID: 99", notification.Message);
    }

    [Fact]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_SetsCreatedAt()
    {
        // Arrange
        var before = DateTime.Now;

        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.True(notification.CreatedAt >= before.AddSeconds(-1));
        Assert.True(notification.CreatedAt <= DateTime.Now.AddSeconds(1));
    }

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.Null(result);
    }

    [Fact]
    public void ReceiveNotification_DequeueFIFO()
    {
        // Arrange
        _sut.SendNotification("A", "1", EntityOperation.CREATE);
        _sut.SendNotification("B", "2", EntityOperation.UPDATE);

        // Act & Assert
        var first = _sut.ReceiveNotification();
        Assert.Equal("A", first!.EntityType);

        var second = _sut.ReceiveNotification();
        Assert.Equal("B", second!.EntityType);

        Assert.Null(_sut.ReceiveNotification()); // empty after dequeue
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert - MarkAsRead is a no-op but should not throw
        var ex = Record.Exception(() => _sut.MarkAsRead(42));
        Assert.Null(ex);
    }

    [Fact]
    public void SendNotification_MultipleMessages_AllRetrievable()
    {
        // Arrange & Act
        for (int i = 0; i < 5; i++)
        {
            _sut.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
        }

        // Assert
        var count = 0;
        while (_sut.ReceiveNotification() != null) count++;
        Assert.Equal(5, count);
    }

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        // Arrange
        var service = new NotificationService();

        // Act & Assert
        var ex = Record.Exception(() => service.Dispose());
        Assert.Null(ex);
    }
}

