+        Assert.Equal("A", first!.EntityType);
+
+        var second = _sut.ReceiveNotification();
+        Assert.Equal("B", second!.EntityType);
+
+        Assert.Null(_sut.ReceiveNotification()); // empty after dequeue
+    }
