+    [Fact]
+    public void SchoolContext_CourseAssignment_HasCompositeKey()
+    {
+        // Arrange
+        using var context = TestDbContextHelper.CreateContext();
+
+        // Act - add instructor and course, then create assignment
+        var instructor = new Instructor { LastName = "Jones", FirstMidName = "Bob", HireDate = DateTime.Now };
+        context.Instructors.Add(instructor);
+        var course = new Course { CourseID = 9999, Title = "Test Course", Credits = 3, DepartmentID = 0 };
+        context.Courses.Add(course);
+        context.SaveChanges();
+
+        var assignment = new CourseAssignment { CourseID = course.CourseID, InstructorID = instructor.ID };
+        context.CourseAssignments.Add(assignment);
+        context.SaveChanges();
+
+        // Assert
+        var found = context.CourseAssignments.Find(course.CourseID, instructor.ID);
+        Assert.NotNull(found);
+    }
+
+    [Fact]
+    public void SchoolContext_CanAddAndRetrieveDepartment()
+    {
+        // Arrange
+        using var context = TestDbContextHelper.CreateContext();
