+        {
+            Name = "Physics",
+            Budget = 200000m,
+            StartDate = DateTime.Parse("2023-01-01")
+        };
+
+        // Act
+        context.Departments.Add(dept);
+        context.SaveChanges();
+
+        // Assert
+        var retrieved = context.Departments.First(d => d.Name == "Physics");
+        Assert.Equal(200000m, retrieved.Budget);
+    }
