+        context.Students.Add(student);
+        context.Instructors.Add(instructor);
+        context.SaveChanges();
+
+        // Act - Both should be retrievable from People
+        var people = context.People.ToList();
+
+        // Assert
+        Assert.Contains(people, p => p is Student && p.LastName == "S1");
+        Assert.Contains(people, p => p is Instructor && p.LastName == "I1");
+    }
+}
